export async function getPullRequestChangedFiles(
	input: {
		owner: string;
		repository: string;
		pullRequestNumber: number;
	},
	env: RhapsodyGitHubEnv = loadRhapsodyGitHubEnv(),
	options?: {
		octokit?: OctokitPullRequestClient;
	},
): Promise<string[]> {
	const octokit = options?.octokit ?? new Octokit({ auth: env.GITHUB_TOKEN });

	const perPage = 100;
	const filenames: string[] = [];
	let page = 1;
	try {
		while (true) {
			const response = await octokit.rest.pulls.listFiles({
				owner: input.owner,
				repo: input.repository,
				pull_number: input.pullRequestNumber,
				per_page: perPage,
				page,
				headers: {
					Accept: "application/vnd.github+json",
					"X-GitHub-Api-Version": "2022-11-28",
				},
			});

			const payload = response.data;
			for (const file of payload) {
				filenames.push(file.filename);
			}

			const linkHeader = response.headers.link;
			if (
				payload.length < perPage ||
				!linkHeader ||
				!linkHeader.includes('rel="next"')
			) {
				return filenames;
			}

			page += 1;
		}
	} catch (error) {
		const status = getErrorStatus(error);
		throw new GitHubPullRequestError(
			status,
			input.owner,
			input.repository,
			"list_files",
			error instanceof Error ? error.message : "request failed",
		);
	}
	return filenames;
}

